+                    })?;
+                let equal = lhs_re == rhs_re && lhs_im == rhs_im;
+                Ok(if primitive == Primitive::Eq {
+                    equal
+                } else {
+                    !equal
+                })
+            }
+            _ => Err(EvalError::TypeMismatch {
+                primitive,
+                detail: "ordered comparison is not supported for complex operands",
+            }),
+        };
+    }
